from copy import deepcopy
from pathlib import Path
from typing import Any

from agentcore.base.data.base_file import BaseFileNode
from agentcore.base.data.utils import IMG_FILE_TYPES, TEXT_FILE_TYPES, parallel_load_data, parse_text_file_to_data
from agentcore.io import BoolInput, FileInput, IntInput, Output
from agentcore.schema.data import Data
from agentcore.services.deps import get_storage_service

_BINARY_FILE_TYPES = [
    *IMG_FILE_TYPES,
    "tiff",
    "bmp",
    "webp",
    "pptx",
    "xlsx",
]


class File(BaseFileNode):

    display_name = "Knowledge Base"
    description = "Select one or more knowledge bases and load their files."
    icon = "file-text"
    name = "File"

    VALID_EXTENSIONS = [*TEXT_FILE_TYPES, *_BINARY_FILE_TYPES]

    _base_inputs = deepcopy(BaseFileNode._base_inputs)

    for input_item in _base_inputs:
        if isinstance(input_item, FileInput) and input_item.name == "path":
            input_item.display_name = "Knowledge Bases"
            input_item.real_time_refresh = True
            break

    inputs = [
        *_base_inputs,
        BoolInput(
            name="use_multithreading",
            display_name="Use Multithreading",
            advanced=True,
            value=True,
            info="Set 'Processing Concurrency' greater than 1 to enable multithreading.",
        ),
        IntInput(
            name="concurrency_multithreading",
            display_name="Processing Concurrency",
            advanced=True,
            info="When multiple files are being processed, the number of files to process concurrently.",
            value=1,
        ),
    ]

    outputs = [
        Output(display_name="Raw Content", name="message", method="load_files_message"),
    ]

    @staticmethod
    def _as_path_list(value: Any) -> list[str]:
        if isinstance(value, str):
            return [value] if value else []
        if isinstance(value, list):
            return [item for item in value if isinstance(item, str) and item]
        if isinstance(value, dict):
            file_path_value = value.get("file_path")
            if isinstance(file_path_value, str):
                return [file_path_value] if file_path_value else []
            if isinstance(file_path_value, list):
                return [item for item in file_path_value if isinstance(item, str) and item]
        return []

    @staticmethod
    def _looks_like_path(path_value: str) -> bool:
        # Stored file paths are like "<user_id>/<kb_name>/<file_name.ext>".
        return "/" in path_value or "\\" in path_value

    def _has_selectable_content(self, path_value: str) -> bool:
        """Return True when a path points to at least one processable file."""
        if not path_value:
            return False

        candidate_paths = [Path(self.resolve_path(path_value))]
        storage_root = Path(str(get_storage_service().data_dir))
        candidate_paths.append(storage_root / path_value)
        if "/" in path_value:
            try:
                candidate_paths.append(Path(self.get_full_path(path_value)))
            except Exception:
                pass
        user_id = getattr(self, "user_id", None)
        if user_id and not path_value.startswith(f"{user_id}/"):
            candidate_paths.append(storage_root / str(user_id) / path_value)

        supported_extensions = set(self.valid_extensions) | set(self.SUPPORTED_BUNDLE_EXTENSIONS)

        resolved_path = next((path for path in candidate_paths if path.exists()), None)
        if resolved_path is None:
            return False

        if resolved_path.is_file():
            suffix = resolved_path.suffix[1:].lower()
            return suffix in supported_extensions

        if resolved_path.is_dir():
            return any(
                candidate.is_file() and candidate.suffix[1:].lower() in supported_extensions
                for candidate in resolved_path.rglob("*")
            )

        return False

    def _filter_selectable_paths(self, path_values: list[str]) -> list[str]:
        return [path_value for path_value in path_values if self._has_selectable_content(path_value)]

    def update_outputs(self, frontend_node: dict, field_name: str, field_value: Any) -> dict:
        """Dynamically show only the relevant output based on the number of files processed."""
        if field_name == "path":
            path_template = frontend_node.get("template", {}).get("path")
            template_file_paths = []
            if isinstance(path_template, dict):
                template_file_paths = self._as_path_list(path_template.get("file_path"))

            incoming_paths = self._as_path_list(field_value)
            # Realtime update sends KB names in field_value; actual storage paths are in template.path.file_path.
            if template_file_paths and (
                not incoming_paths or all(not self._looks_like_path(path) for path in incoming_paths)
            ):
                selected_paths = template_file_paths
            else:
                selected_paths = incoming_paths

            filtered_paths = self._filter_selectable_paths(selected_paths)
            invalid_paths = [path for path in selected_paths if path not in filtered_paths]

            if invalid_paths:
                self.log(
                    "Ignoring unresolved/unsupported knowledge base selections: "
                    + ", ".join(invalid_paths)
                )
                # Keep selection stable; avoid UI popup/revert for legacy path tokens.
                if not filtered_paths and selected_paths:
                    filtered_paths = selected_paths

            if isinstance(path_template, dict):
                path_template["file_path"] = filtered_paths

            field_value = filtered_paths

            # Add outputs based on the number of files in the path
            if len(field_value) == 0:
                frontend_node["outputs"] = []
                return frontend_node

            frontend_node["outputs"] = []

            if len(field_value) == 1:
                # We need to check if the file is structured content
                file_path = frontend_node["template"]["path"]["file_path"][0]
                if file_path.endswith((".csv", ".xlsx", ".parquet")):
                    frontend_node["outputs"].append(
                        Output(display_name="Structured Content", name="dataframe", method="load_files_structured"),
                    )
                elif file_path.endswith(".json"):
                    frontend_node["outputs"].append(
                        Output(display_name="Structured Content", name="json", method="load_files_json"),
                    )

            # Always include path output so OCR and other downstream components can connect
            frontend_node["outputs"].append(
                Output(display_name="Knowledge Base", name="path", method="load_files_path"),
            )

            if len(field_value) > 1:
                # For multiple files, also show the combined files output
                frontend_node["outputs"].append(
                    Output(display_name="Knowledge Bases", name="dataframe", method="load_files"),
                )

        return frontend_node

    def process_files(self, file_list: list[BaseFileNode.BaseFile]) -> list[BaseFileNode.BaseFile]:
        """Processes files either sequentially or in parallel, depending on concurrency settings.

        Args:
            file_list (list[BaseFileNode.BaseFile]): List of files to process.

        Returns:
            list[BaseFileNode.BaseFile]: Updated list of files with merged data.
        """

        def process_file(file_path: str, *, silent_errors: bool = False) -> Data | None:
            """Processes a single file and returns its Data object."""
            ext = Path(file_path).suffix.lstrip(".").lower()

            # Binary files (images, pptx, xlsx, etc.) can't be parsed as text.
            # Return a Data object with the file path so downstream components
            # (e.g. Document OCR Extractor) can consume them.
            if ext in _BINARY_FILE_TYPES:
                return Data(
                    text=file_path,
                    data={"file_path": file_path, "file_type": ext},
                )

            try:
                return parse_text_file_to_data(file_path, silent_errors=silent_errors)
            except FileNotFoundError as e:
                msg = f"File not found: {file_path}. Error: {e}"
                self.log(msg)
                if not silent_errors:
                    raise
                return None
            except Exception as e:
                msg = f"Unexpected error processing {file_path}: {e}"
                self.log(msg)
                if not silent_errors:
                    raise
                return None

        if not file_list:
            msg = "No files to process."
            raise ValueError(msg)

        concurrency = 1 if not self.use_multithreading else max(1, self.concurrency_multithreading)
        file_count = len(file_list)

        parallel_processing_threshold = 2
        if concurrency < parallel_processing_threshold or file_count < parallel_processing_threshold:
            if file_count > 1:
                self.log(f"Processing {file_count} files sequentially.")
            processed_data = [process_file(str(file.path), silent_errors=self.silent_errors) for file in file_list]
        else:
            self.log(f"Starting parallel processing of {file_count} files with concurrency: {concurrency}.")
            file_paths = [str(file.path) for file in file_list]
            processed_data = parallel_load_data(
                file_paths,
                silent_errors=self.silent_errors,
                load_function=process_file,
                max_concurrency=concurrency,
            )

        # Use rollup_basefile_data to merge processed data with BaseFile objects
        return self.rollup_data(file_list, processed_data)

from agentcore.custom import Node
import json
import re
import time


FILLER_RE = re.compile(
    r"\b(please|can you|could you|show me|i want to see|i need|"
    r"tell me|give me|display|find me|help me)\b",
    re.IGNORECASE,
)

INTENT_PATTERNS = {
    "enumerate": [r"\blist\b", r"\bshow all\b", r"\bwhat are\b", r"\bwhich\b", r"\bdistinct\b"],
    "top_n": [r"\btop\s+\d+\b", r"\bhighest\s+\d+\b", r"\blargest\s+\d+\b"],
    "bottom_n": [r"\bbottom\s+\d+\b", r"\blowest\s+\d+\b", r"\bsmallest\s+\d+\b"],
    "count": [r"\bhow many\b", r"\bnumber of\b", r"\bcount\b"],
    "average": [r"\baverage\b", r"\bavg\b", r"\bmean\b"],
    "time_series": [r"\bmonthly\b", r"\bquarterly\b", r"\bweekly\b", r"\bdaily\b"],
    "trend": [r"\btrend\b", r"\bover time\b", r"\bgrowth\b"],
    "comparison": [r"\bcompare\b", r"\bvs\b", r"\bversus\b", r"\bdifference\b"],
    "aggregation": [r"\btotal\b", r"\bsum\b", r"\boverall\b"],
}


class CodeEditorNode(Node):
    display_name = "Talk to Data Pipeline"
    description = "NL-to-SQL pipeline: analyzes query, links schema, builds context, generates and executes SQL. Use this tool when the user asks a data question."
    icon = "database"
    name = "TalkToDataPipeline"

    inputs = [
        MessageTextInput(
            name="input_value",
            display_name="User Question",
            info="The natural language question about your data.",
            tool_mode=True,
        ),
        HandleInput(
            name="knowledge_context",
            display_name="Knowledge Context",
            input_types=["Data"],
            info="From Knowledge Processor.",
            required=False,
        ),
        HandleInput(
            name="db_connection",
            display_name="Database Connection",
            input_types=["Data"],
            info="From Database Connector (host, port, credentials, schema DDL).",
            required=True,
        ),
        HandleInput(
            name="llm",
            display_name="Language Model",
            input_types=["LanguageModel"],
            info="LLM for Schema Linking and SQL Generation.",
            required=True,
        ),
        IntInput(name="max_rows", display_name="Max Result Rows", value=100),
        IntInput(name="query_timeout", display_name="Query Timeout (seconds)", value=30),
        DropdownInput(
            name="sql_dialect",
            display_name="SQL Dialect",
            options=["auto", "oracle", "postgresql", "mysql", "sqlserver"],
            value="auto",
        ),
        MultilineInput(name="extra_rules", display_name="Extra SQL Rules", value=""),
        IntInput(name="max_examples", display_name="Max Few-Shot Examples", value=15),
        BoolInput(name="enable_retry", display_name="Enable SQL Retry", value=True),
        IntInput(name="max_retries", display_name="Max Retry Attempts", value=2),
    ]

    outputs = [
        Output(display_name="Results", name="output", method="build_output"),
    ]

    def build_output(self) -> Message:
        raw_query = self.input_value or ""
        if raw_query.startswith('"') and raw_query.endswith('"'):
            raw_query = raw_query[1:-1]
        if not raw_query.strip():
            return Message(text="No query provided.")

        kc = self.knowledge_context
        knowledge = {}
        if kc and kc != "":
            knowledge = kc.data if isinstance(kc, Data) else (kc if isinstance(kc, dict) else {})

        db = self.db_connection
        db_data = db.data if isinstance(db, Data) else (db if isinstance(db, dict) else {})
        if not db_data:
            return Message(text="Error: No database connection provided.")

        provider = self.sql_dialect if self.sql_dialect != "auto" else db_data.get("provider", "postgresql")
        schema_ddl = db_data.get("schema_ddl", "")

        try:
            stage1 = self._stage1_query_analyzer(raw_query, knowledge)
            stage2 = self._stage2_schema_linker(stage1, knowledge, db_data)
            stage3 = self._stage3_context_builder(stage2, knowledge, provider, schema_ddl)
            stage4 = self._stage4_sql_generator(stage3)
            result_msg = self._stage5_sql_processor(stage4, db_data, provider)
            return result_msg
        except Exception as e:
            return Message(text=f"Pipeline error: {e}")

    def _stage1_query_analyzer(self, raw, knowledge):
        text = raw.strip()
        cleaned = FILLER_RE.sub("", text)
        cleaned = re.sub(r"\s{2,}", " ", cleaned).strip()
        if len(cleaned) < 3:
            cleaned = text

        query_lower = cleaned.lower()
        scores = []
        for intent_name, patterns in INTENT_PATTERNS.items():
            for pat in patterns:
                if re.search(pat, query_lower):
                    scores.append((intent_name, 0.6))
                    break
        scores.sort(key=lambda x: x[1], reverse=True)
        primary_intent = scores[0][0] if scores else "unknown"

        return {
            "raw_query": raw,
            "normalized_query": cleaned,
            "intent": {"primary_intent": primary_intent},
        }

    def _stage2_schema_linker(self, ctx, knowledge, db_data):
        normalized_query = ctx.get("normalized_query", ctx.get("raw_query", ""))
        synonym_map = knowledge.get("synonym_map", {})

        syn_lines = [f'  "{t}" -> {info.get("column", "?")}' for t, info in list(synonym_map.items())[:100]]

        prompt = f"""You are a schema linking agent. Resolve natural language terms to database column names.

SYNONYM MAP:
{chr(10).join(syn_lines) if syn_lines else '  (none)'}

User query: "{normalized_query}"

Respond with JSON:
{{"resolved_columns": {{}}, "suggested_filters": [], "suggested_groupby": [], "suggested_orderby": null, "suggested_limit": null}}

Return ONLY JSON."""

        schema_linking = {}
        try:
            response = self.llm.invoke(prompt)
            text = response.content if hasattr(response, "content") else str(response)
            text = text.strip()
            if text.startswith("```json"):
                text = text[7:]
            if text.startswith("```"):
                text = text[3:]
            if text.endswith("```"):
                text = text[:-3]
            schema_linking = json.loads(text.strip())
        except Exception as e:
            schema_linking = {"error": str(e)}

        return {**ctx, "schema_linking": schema_linking}

    def _stage3_context_builder(self, ctx, knowledge, provider, schema_ddl):
        schema_linking = ctx.get("schema_linking", {})
        intent_result = ctx.get("intent", {})
        normalized_query = ctx.get("normalized_query", "")
        mr = self.max_rows

        sections = [
            f"You are an expert SQL analyst for {provider.upper()} databases. "
            "Generate a precise SQL query for the question below.",
            f"\n**Database Schema:**\n```sql\n{schema_ddl}\n```",
        ]

        resolved = schema_linking.get("resolved_columns", {})
        if resolved:
            lines = [f'  "{t}" -> {c}' for t, c in resolved.items()]
            sections.append("\n**Resolved Columns:**\n" + "\n".join(lines))

        sug_f = schema_linking.get("suggested_filters", [])
        if sug_f:
            sections.append("Suggested filters: " + ", ".join(str(f) for f in sug_f))

        if intent_result.get("primary_intent", "unknown") != "unknown":
            sections.append(f"\n**Intent:** {intent_result['primary_intent']}")

        examples = knowledge.get("examples", [])
        selected = examples[:self.max_examples]
        if selected:
            ex_lines = []
            for ex in selected:
                q = ex.get("question", "")
                s = ex.get("sql", "")
                if q and s:
                    ex_lines.append(f"Q: {q}\nSQL: {s}")
            if ex_lines:
                sections.append("\n**Examples:**\n" + "\n\n".join(ex_lines))

        adc = knowledge.get("additional_domain_context", "")
        if adc:
            sections.append(f"\n**Domain Context:**\n{adc}")

        limit_syntax = f"FETCH FIRST {mr} ROWS ONLY" if provider == "oracle" else f"LIMIT {mr}"
        sections.append(f"\n**SQL Rules:**\n1. SELECT only\n2. Use exact column names\n3. GROUP BY for aggregations\n4. Use {limit_syntax} to cap results\n5. Return ONLY the SQL, no explanations")

        if self.extra_rules and self.extra_rules.strip():
            sections.append(self.extra_rules.strip())

        sections.append(f"\n**User Question:** {normalized_query}")
        sections.append("\n**SQL Query:**")

        return {
            **ctx,
            "prompt_text": "\n".join(sections),
            "provider": provider,
            "schema_ddl": schema_ddl,
        }

    def _stage4_sql_generator(self, ctx):
        prompt_text = ctx.get("prompt_text", "")
        if not prompt_text:
            return {**ctx, "generated_sql": "", "error": True, "message": "Empty prompt."}
        try:
            response = self.llm.invoke(prompt_text)
            raw = response.content if hasattr(response, "content") else str(response)
            sql = raw.strip()
            if sql.startswith("```sql"):
                sql = sql[6:]
            if sql.startswith("```"):
                sql = sql[3:]
            if sql.endswith("```"):
                sql = sql[:-3]
            sql = sql.strip()
        except Exception as e:
            return {**ctx, "generated_sql": "", "error": True, "message": f"LLM failed: {e}"}
        return {**ctx, "generated_sql": sql}

    def _stage5_sql_processor(self, ctx, db_data, provider):
        if ctx.get("error"):
            return Message(text=f"Error: {ctx.get('message', 'Unknown')}")

        sql = ctx.get("generated_sql", "")
        if not sql:
            return Message(text="Error: No SQL generated.")

        if provider == "oracle":
            sql = sql.rstrip(";")

        mr = self.max_rows
        conn_params = {k: v for k, v in db_data.items() if k != "schema_ddl"}

        try:
            rows, columns = self._execute_sql(sql, conn_params, provider)
        except Exception as e:
            if self.enable_retry:
                fixed_sql = self._judge_and_fix_sql(sql, str(e), ctx, provider)
                if fixed_sql:
                    try:
                        rows, columns = self._execute_sql(fixed_sql, conn_params, provider)
                        sql = fixed_sql
                    except Exception as e2:
                        return Message(text=f"SQL failed after retry:\n```sql\n{fixed_sql}\n```\nError: {e2}")
                else:
                    return Message(text=f"SQL failed:\n```sql\n{sql}\n```\nError: {e}")
            else:
                return Message(text=f"SQL failed:\n```sql\n{sql}\n```\nError: {e}")

        if not rows:
            return Message(text=f"Query returned 0 rows.\n```sql\n{sql}\n```")

        data_json = {"columns": columns, "rows": rows[:mr]}
        table_lines = ["| " + " | ".join(columns) + " |"]
        table_lines.append("| " + " | ".join("---" for _ in columns) + " |")
        for row in rows[:mr]:
            table_lines.append("| " + " | ".join(str(v) if v is not None else "—" for v in row) + " |")

        parts = [
            "\n".join(table_lines),
            f"\n*{len(rows)} rows returned*",
            f"\n```sql\n{sql}\n```",
            f"\n<!-- data_json:{json.dumps(data_json)} -->",
        ]
        return Message(text="\n".join(parts))

    def _execute_sql(self, sql, conn_params, provider):
        if provider == "oracle":
            import oracledb
            dsn = oracledb.makedsn(conn_params.get("host"), conn_params.get("port", 1521), service_name=conn_params.get("service_name", ""))
            conn = oracledb.connect(user=conn_params.get("user"), password=conn_params.get("password"), dsn=dsn)
        elif provider == "postgresql":
            import psycopg2
            conn = psycopg2.connect(host=conn_params.get("host"), port=conn_params.get("port", 5432),
                                    dbname=conn_params.get("database"), user=conn_params.get("user"), password=conn_params.get("password"))
        elif provider == "mysql":
            import mysql.connector
            conn = mysql.connector.connect(host=conn_params.get("host"), port=conn_params.get("port", 3306),
                                           database=conn_params.get("database"), user=conn_params.get("user"), password=conn_params.get("password"))
        else:
            raise ValueError(f"Unsupported provider: {provider}")

        try:
            cur = conn.cursor()
            cur.execute(sql)
            columns = [desc[0] for desc in cur.description] if cur.description else []
            rows = cur.fetchmany(self.max_rows)
            rows = [list(r) for r in rows]
            return rows, columns
        finally:
            conn.close()

    def _judge_and_fix_sql(self, failed_sql, error_msg, ctx, provider):
        schema_ddl = ctx.get("schema_ddl", "")
        user_question = ctx.get("normalized_query", ctx.get("raw_query", ""))

        prompt = f"""You are a SQL debugger for {provider.upper()} databases.

**User Question:** {user_question}

**Failed SQL:**
```sql
{failed_sql}
```

**Error:** {error_msg}

**Schema:**
```sql
{schema_ddl}
```

Fix the SQL. Return ONLY the corrected SQL query."""

        try:
            response = self.llm.invoke(prompt)
            raw = response.content if hasattr(response, "content") else str(response)
            sql = raw.strip()
            if sql.startswith("```sql"):
                sql = sql[6:]
            if sql.startswith("```"):
                sql = sql[3:]
            if sql.endswith("```"):
                sql = sql[:-3]
            return sql.strip()
        except Exception:
            return None

from agentcore.custom import Node
import json
import re
import os


def _read_file(path):
    path = path.strip().strip('"').strip("'")
    if not os.path.isfile(path):
        return None
    try:
        with open(path, "r", encoding="utf-8") as f:
            return f.read()
    except Exception:
        return None


def _parse_content(text, filename=""):
    text = text.strip()
    if not text:
        return None
    if text.startswith(("{", "[")):
        try:
            return json.loads(text)
        except json.JSONDecodeError:
            pass
    try:
        import yaml
        result = yaml.safe_load(text)
        if isinstance(result, (dict, list)):
            return result
    except Exception:
        pass
    try:
        return json.loads(text)
    except Exception:
        pass
    return None


def _detect_type_by_filename(filename):
    if not filename:
        return None
    base = os.path.basename(filename).rsplit(".", 1)[0].lower()
    base = re.sub(r'[^a-z0-9]', '', base)
    keywords_map = [
        (["synonym"], "synonyms"),
        (["schema", "column"], "schema"),
        (["example", "fewshot"], "examples"),
        (["rule", "businessrule"], "business_rules"),
        (["context", "domain"], "domain_context"),
    ]
    for keywords, slot in keywords_map:
        for kw in keywords:
            if kw in base:
                return slot
    return None


def _detect_type(parsed, filename=""):
    slot = _detect_type_by_filename(filename)
    if slot:
        return slot
    if not isinstance(parsed, dict):
        if isinstance(parsed, list) and parsed and isinstance(parsed[0], dict):
            if "question" in parsed[0] or "sql" in parsed[0]:
                return "examples"
        return None
    keys = set(parsed.keys())
    if "synonyms" in keys or "column_synonyms" in keys:
        return "synonyms"
    if "columns" in keys:
        return "schema"
    if "examples" in keys:
        return "examples"
    if "rules" in keys or "metrics" in keys:
        return "business_rules"
    return None


class CodeEditorNode(Node):
    display_name = "Knowledge Processor"
    description = "Processes knowledge artifacts (YAML/JSON) into a unified context dict."
    icon = "brain"
    name = "KnowledgeProcessor"

    inputs = [
        MessageTextInput(
            name="input_value",
            display_name="Raw Knowledge Text",
            info="Paste raw JSON/YAML text here for quick testing.",
            tool_mode=False,
        ),
        HandleInput(
            name="knowledge_base",
            display_name="Knowledge Base",
            input_types=["Data", "Message"],
            info="From Knowledge Base component.",
            required=False,
        ),
        MultilineInput(name="additional_rules", display_name="Additional Business Rules", value=""),
        MultilineInput(name="additional_context", display_name="Additional Domain Context", value=""),
    ]

    outputs = [
        Output(display_name="Knowledge Context", name="output", method="build_output"),
    ]

    def _extract_files_from_kb(self, kb):
        files = []
        text = None
        if hasattr(kb, "text") and isinstance(kb.text, str):
            text = kb.text.strip()
        elif hasattr(kb, "data"):
            inner = kb.data
            if isinstance(inner, str):
                text = inner.strip()
            elif isinstance(inner, dict):
                text = (inner.get("text") or inner.get("content") or "").strip()
        elif isinstance(kb, str):
            text = kb.strip()
        if not text:
            return files

        text_lines = [l.strip() for l in text.split('\n') if l.strip()]
        sample = text_lines[:5]
        looks_like_paths = len(sample) > 0 and all(
            any(l.lower().endswith(ext) for ext in ('.yaml', '.yml', '.json', '.txt'))
            and ('/' in l or '\\' in l)
            for l in sample
        )

        if looks_like_paths:
            for line in text_lines:
                path = line.strip().strip('"').strip("'")
                content = _read_file(path)
                if content:
                    filename = os.path.basename(path)
                    parsed = _parse_content(content, filename)
                    if parsed is not None:
                        files.append((filename, parsed))
        else:
            parsed = _parse_content(text)
            if parsed is not None:
                files.append(("", parsed))
        return files

    def build_output(self) -> Data:
        all_files = []

        kb = self.knowledge_base
        if kb and kb != "":
            all_files.extend(self._extract_files_from_kb(kb))

        text_in = self.input_value
        if text_in and isinstance(text_in, str) and text_in.strip():
            parsed = _parse_content(text_in.strip())
            if parsed is not None:
                all_files.append(("text_input", parsed))

        if not all_files:
            self.status = "No knowledge inputs parsed"
            return Data(data={"error": True, "message": "No knowledge inputs parsed."})

        slots = {}
        for filename, parsed in all_files:
            slot = _detect_type(parsed, filename)
            if slot:
                slots[slot] = parsed

        synonym_map = {}
        syn_data = slots.get("synonyms", {})
        if isinstance(syn_data, dict):
            for col_name, syn_info in syn_data.get("column_synonyms", syn_data).items():
                syns = syn_info if isinstance(syn_info, list) else (syn_info.get("synonyms", []) if isinstance(syn_info, dict) else [])
                for s in syns:
                    synonym_map[str(s).lower().strip()] = {"column": col_name}

        examples = []
        ex_data = slots.get("examples")
        if ex_data:
            ex_list = ex_data if isinstance(ex_data, list) else ex_data.get("examples", [])
            for ex in (ex_list if isinstance(ex_list, list) else []):
                if isinstance(ex, dict):
                    examples.append({
                        "question": ex.get("question") or ex.get("input", ""),
                        "sql": ex.get("sql") or ex.get("output", ""),
                    })

        business_rules = slots.get("business_rules", {})
        schema_info = slots.get("schema", {})
        additional_rules = (self.additional_rules or "").strip()
        additional_context = (self.additional_context or "").strip()

        dc = slots.get("domain_context")
        if dc:
            dc_text = json.dumps(dc, indent=2) if isinstance(dc, dict) else str(dc)
            additional_context = (additional_context + "\n\n" + dc_text).strip()

        context = {
            "synonym_map": synonym_map,
            "examples": examples,
            "business_rules": business_rules,
            "schema_info": schema_info,
            "additional_business_rules": additional_rules,
            "additional_domain_context": additional_context,
            "knowledge_files_loaded": len(slots),
            "synonym_count": len(synonym_map),
            "example_count": len(examples),
        }

        self.status = f"Loaded {len(slots)} artifacts | {len(synonym_map)} synonyms, {len(examples)} examples"

        parts = [
            f"**Knowledge Processor**\n",
            f"**Artifacts Loaded:** {len(slots)}",
            f"  - Synonyms: {len(synonym_map)}",
            f"  - Examples: {len(examples)}",
        ]

        result = Data(data=context)
        result.text_key = "summary"
        context["summary"] = "\n".join(parts)
        return result

from agentcore.custom import Node
import json
import re
import base64
import io


CHART_PLANNER_PROMPT = """You are a data visualization expert. Analyze the data and plan the best chart.

**User Request:** {user_request}

**Data:**
{data_preview}

**Available chart types:** bar, bar_horizontal, line, pie, scatter, stacked_bar, table

**Respond with ONLY this JSON:**
{{
    "chart_type": "bar",
    "title": "Descriptive title",
    "x_column": 0,
    "y_columns": [1],
    "x_label": "X axis label",
    "y_label": "Y axis label",
    "sort_by_value": true,
    "sort_descending": true,
    "top_n": null,
    "annotations": []
}}

Rules:
- x_column = category/label column index, y_columns = numeric column index(es)
- Pie: 2-8 categories only. Bar: default for comparisons. Line: time series. Table: fallback.
- title/labels should be human readable, not raw column names.

Return ONLY the JSON."""


COLORS = ["#1e3a5f", "#2e86ab", "#a23b72", "#f18f01", "#c73e1d",
          "#44bba4", "#e94f37", "#5b8c5a", "#8338ec", "#ff006e"]


def _try_parse_data_json(text):
    comment_match = re.search(r'<!--\s*data_json:(.*?)\s*-->', text, re.DOTALL)
    if comment_match:
        try:
            data = json.loads(comment_match.group(1).strip())
            if data.get("columns") and data.get("rows"):
                return data, text[comment_match.end():].strip()
        except json.JSONDecodeError:
            pass
    try:
        raw = json.loads(text.strip())
        if isinstance(raw, dict) and raw.get("columns") and raw.get("rows"):
            return raw, ""
    except (json.JSONDecodeError, ValueError):
        pass
    return None, text


def _try_parse_markdown_table(text):
    lines = text.strip().split("\n")
    table_lines = [l for l in lines if l.strip().startswith("|")]
    if len(table_lines) < 3:
        return None
    header = table_lines[0]
    columns = [c.strip() for c in header.split("|") if c.strip()]
    if not columns:
        return None
    data_start = 1
    for i in range(1, len(table_lines)):
        if re.match(r'^[\s|:-]+$', table_lines[i]):
            data_start = i + 1
        else:
            break
    rows = []
    for line in table_lines[data_start:]:
        cells = [c.strip() for c in line.split("|") if c.strip()]
        if len(cells) != len(columns):
            continue
        parsed_row = []
        for cell in cells:
            clean = cell.replace(",", "").strip()
            if not clean:
                parsed_row.append(None)
            else:
                try:
                    parsed_row.append(float(clean) if "." in clean else int(clean))
                except ValueError:
                    parsed_row.append(cell)
        rows.append(parsed_row)
    return {"columns": columns, "rows": rows} if rows else None


def _render_interactive_chart(plan, columns, rows):
    x_col = plan.get("x_column", 0)
    y_cols = plan.get("y_columns", [1])
    title = plan.get("title", "Chart").replace("'", "")
    chart_type = plan.get("chart_type", "bar")
    sort_by_value = plan.get("sort_by_value", False)
    sort_desc = plan.get("sort_descending", True)

    def _safe_float(v):
        try:
            return float(str(v).replace(",", "")) if v is not None else 0
        except (ValueError, TypeError):
            return 0

    work_rows = list(rows)
    if sort_by_value and y_cols:
        y_idx = y_cols[0] if y_cols[0] < len(columns) else 1
        work_rows.sort(key=lambda r: _safe_float(r[y_idx] if y_idx < len(r) else 0), reverse=sort_desc)
    top_n = plan.get("top_n")
    if top_n and len(work_rows) > top_n:
        work_rows = work_rows[:top_n]

    labels = [str(r[x_col])[:30].replace("'", "\\'") if x_col < len(r) else "?" for r in work_rows]
    cjs_map = {"bar": "bar", "bar_horizontal": "bar", "line": "line", "pie": "pie", "scatter": "scatter", "stacked_bar": "bar"}
    cjs_type = cjs_map.get(chart_type, "bar")
    is_horizontal = chart_type == "bar_horizontal"

    labels_js = "[" + ",".join(f"'{l}'" for l in labels) + "]"
    datasets_parts = []
    for i, y_idx in enumerate(y_cols):
        vals = [_safe_float(r[y_idx] if y_idx < len(r) else 0) for r in work_rows]
        vals_js = "[" + ",".join(str(v) for v in vals) + "]"
        lbl = columns[y_idx].replace("_", " ").title().replace("'", "") if y_idx < len(columns) else f"Series {i+1}"
        c = COLORS[i % len(COLORS)]
        if cjs_type == "pie":
            bg_js = "[" + ",".join(f"'{COLORS[j % len(COLORS)]}'" for j in range(len(vals))) + "]"
            datasets_parts.append(f"{{label:'{lbl}',data:{vals_js},backgroundColor:{bg_js},borderWidth:2,borderColor:'#fff'}}")
        else:
            datasets_parts.append(f"{{label:'{lbl}',data:{vals_js},backgroundColor:'{c}cc',borderColor:'{c}',borderWidth:1}}")

    idx_axis = "'y'" if is_horizontal else "'x'"
    stacked = "true" if chart_type == "stacked_bar" else "false"
    show_legend = "true" if (cjs_type == "pie" or len(y_cols) > 1) else "false"
    x_label = plan.get("x_label", "").replace("'", "")
    y_label = plan.get("y_label", "").replace("'", "")
    height = max(300, len(work_rows) * 35) if is_horizontal else 400

    html = "".join([
        "<!DOCTYPE html><html><head>",
        "<script src='https://cdn.jsdelivr.net/npm/chart.js@4.4.7/dist/chart.umd.min.js'></script>",
        "<style>body{margin:0;padding:8px;font-family:system-ui;background:#fff}.wrap{max-width:700px;margin:0 auto}</style>",
        "</head><body><div class='wrap'><canvas id='c'></canvas></div><script>",
        f"new Chart(document.getElementById('c'),{{type:'{cjs_type}',",
        f"data:{{labels:{labels_js},datasets:[{','.join(datasets_parts)}]}},",
        f"options:{{indexAxis:{idx_axis},responsive:true,",
        f"plugins:{{title:{{display:true,text:'{title}',font:{{size:14,weight:'bold'}}}},legend:{{display:{show_legend}}}}},",
        f"scales:{{x:{{stacked:{stacked},title:{{display:{'true' if x_label else 'false'},text:'{x_label}'}}}},",
        f"y:{{stacked:{stacked},title:{{display:{'true' if y_label else 'false'},text:'{y_label}'}}}}}}}}}});",
        "</script></body></html>",
    ])
    srcdoc = html.replace("&", "&amp;")
    return f'<iframe srcdoc="{srcdoc}" width="100%" height="{height}" frameborder="0" style="border:1px solid #e0e0e0;border-radius:8px;max-width:750px"></iframe>'


class CodeEditorNode(Node):
    display_name = "Data Visualizer"
    description = (
        "ONLY use this tool when the user EXPLICITLY asks to plot, chart, graph, or visualize data. "
        "Do NOT call this for normal data queries. Pass data_json and chart instructions as input."
    )
    icon = "bar-chart-3"
    name = "DataVisualizer"

    inputs = [
        MessageTextInput(
            name="input_value",
            display_name="Data + Instructions",
            info="Data (JSON, markdown table) + optional chart instructions.",
            tool_mode=True,
        ),
        HandleInput(
            name="llm",
            display_name="Language Model",
            input_types=["LanguageModel"],
            info="Optional LLM for smart chart planning.",
            required=False,
        ),
        DropdownInput(
            name="render_mode",
            display_name="Render Mode",
            options=["interactive", "image"],
            value="interactive",
        ),
    ]

    outputs = [
        Output(display_name="Chart", name="output", method="build_output"),
    ]

    def build_output(self) -> Message:
        raw_input = self.input_value or ""
        if not raw_input.strip():
            return Message(text="No data provided. Run a data query first, then ask to chart it.")

        data = None
        instructions = raw_input

        parsed, remaining = _try_parse_data_json(raw_input)
        if parsed:
            data = parsed
            instructions = remaining or "visualize this data"

        if not data:
            parsed = _try_parse_markdown_table(raw_input)
            if parsed:
                data = parsed
                non_table = [l for l in raw_input.split("\n") if not l.strip().startswith("|")]
                instructions = "\n".join(non_table).strip() or "visualize this data"

        if not data or not data.get("columns") or not data.get("rows"):
            return Message(text="Could not extract chartable data. Please provide a data table or JSON with columns/rows.")

        columns = data["columns"]
        rows = data["rows"]
        plan = self._auto_plan(columns, rows, instructions)

        if self.llm and self.llm != "":
            try:
                llm_plan = self._llm_plan(columns, rows, instructions)
                if llm_plan and llm_plan.get("chart_type"):
                    plan = llm_plan
            except Exception:
                pass

        try:
            if plan.get("chart_type") == "table":
                return self._render_table(columns, rows)

            data_comment = f"\n<!-- data_json:{json.dumps({'columns': columns, 'rows': rows})} -->"

            if self.render_mode == "interactive":
                iframe = _render_interactive_chart(plan, columns, rows)
                self.status = f"{plan.get('chart_type', 'bar')} | {len(rows)} rows"
                return Message(text=iframe + data_comment)

            import matplotlib
            matplotlib.use("Agg")
            import matplotlib.pyplot as plt

            fig, ax = plt.subplots(figsize=(8, 4))
            chart_type = plan.get("chart_type", "bar")
            x_col = plan.get("x_column", 0)
            y_cols = plan.get("y_columns", [1])
            labels = [str(r[x_col])[:25] if x_col < len(r) else "?" for r in rows]

            def _sf(v):
                try:
                    return float(str(v).replace(",", "")) if v is not None else 0
                except:
                    return 0

            for i, y_idx in enumerate(y_cols):
                vals = [_sf(r[y_idx] if y_idx < len(r) else 0) for r in rows]
                if chart_type == "line":
                    ax.plot(labels, vals, marker="o", color=COLORS[i % len(COLORS)])
                elif chart_type == "bar_horizontal":
                    ax.barh(labels, vals, color=COLORS[i % len(COLORS)])
                else:
                    ax.bar(labels, vals, color=[COLORS[j % len(COLORS)] for j in range(len(vals))])

            ax.set_title(plan.get("title", "Chart"), fontsize=14, fontweight="bold")
            plt.xticks(rotation=45, ha="right", fontsize=9)
            plt.tight_layout()

            buf = io.BytesIO()
            fig.savefig(buf, format="png", dpi=120, bbox_inches="tight")
            buf.seek(0)
            b64 = base64.b64encode(buf.read()).decode("utf-8")
            buf.close()
            plt.close(fig)

            self.status = f"{chart_type} | {len(rows)} rows | image"
            return Message(text=f"![{plan.get('title', 'Chart')}](data:image/png;base64,{b64})" + data_comment)

        except Exception as e:
            return self._render_table(columns, rows, error=str(e))

    def _auto_plan(self, columns, rows, request=""):
        text_cols = []
        numeric_cols = []
        for i, col in enumerate(columns):
            is_num = False
            for row in rows[:10]:
                if i < len(row) and row[i] is not None:
                    is_num = isinstance(row[i], (int, float))
                    break
            (numeric_cols if is_num else text_cols).append(i)

        x_col = text_cols[0] if text_cols else 0
        y_cols = numeric_cols[:1] if numeric_cols else ([1] if len(columns) > 1 else [0])
        chart_type = "bar"
        if len(rows) > 15:
            chart_type = "bar_horizontal"
        req_lower = request.lower()
        if any(w in req_lower for w in ("line", "trend", "time", "monthly")):
            chart_type = "line"
        elif any(w in req_lower for w in ("pie", "share", "proportion")):
            chart_type = "pie"

        return {
            "chart_type": chart_type, "title": "Data Visualization",
            "x_column": x_col, "y_columns": y_cols,
            "x_label": columns[x_col] if x_col < len(columns) else "",
            "y_label": columns[y_cols[0]] if y_cols and y_cols[0] < len(columns) else "",
            "sort_by_value": True, "sort_descending": True, "top_n": None,
        }

    def _llm_plan(self, columns, rows, request):
        preview = f"Columns: {columns}\nTotal rows: {len(rows)}\nSample:\n"
        for row in rows[:8]:
            preview += f"  {row}\n"
        prompt = CHART_PLANNER_PROMPT.format(user_request=request, data_preview=preview)
        response = self.llm.invoke(prompt)
        text = response.content if hasattr(response, "content") else str(response)
        text = text.strip()
        if text.startswith("```json"):
            text = text[7:]
        if text.startswith("```"):
            text = text[3:]
        if text.endswith("```"):
            text = text[:-3]
        return json.loads(text.strip())

    def _render_table(self, columns, rows, error=None):
        lines = ["| " + " | ".join(columns) + " |"]
        lines.append("| " + " | ".join("---" for _ in columns) + " |")
        for row in rows[:100]:
            lines.append("| " + " | ".join(str(v) if v is not None else "—" for v in row) + " |")
        text = "\n".join(lines)
        if error:
            text = f"*Chart rendering failed ({error}), showing table:*\n\n" + text
        return Message(text=text)
